  "options": [
    {
      "text": "¡Hola, !",
      "hint": "Piensa en qué le sucede a 'philosopher' después de que se mueve"
    },
    {
      "text": "¡Hola, Zeno of Citium!",
      "hint": "Una vez que un valor se mueve, ¿podemos todavía usarlo?"
